INSERT INTO `faq_items` (`id`, `question`, `answer`, `sort_order`, `created_at`, `updated_at`) VALUES
(1, 'How do I change my profile picture?', 'Go to Profile > Edit Profile and tap your avatar to upload a new image.', 1, '2026-02-20 13:30:38', '2026-02-20 13:30:38'),
(2, 'How do I block a user?', 'Open the user\'s profile and tap the menu, then select Block.', 2, '2026-02-20 13:30:38', '2026-02-20 13:30:38'),
(3, 'How do I create a group chat?', 'Go to Contacts > Create Group, add a name and select members.', 3, '2026-02-20 13:30:38', '2026-02-20 13:30:38');
